<?php
declare(strict_types=1);
require_once __DIR__.'/auth.php';require_once __DIR__.'/notificaciones.php';require_once __DIR__.'/audit.php';require_once __DIR__.'/config/services.php';require_once __DIR__.'/imap_config.php';

function comunicacionUsuario(PDO $pdo,int $id):?array{$q=$pdo->prepare("SELECT id,nombre,apellido,correo,rol FROM usuarios WHERE id=:id AND estado='activo' AND deleted_at IS NULL");$q->execute(['id'=>$id]);return$q->fetch()?:null;}
function etiquetaRolComunicacion(string $rol):string{return match($rol){'usuario'=>'Estudiante','docente'=>'Docente','admin'=>'Administración',default=>'Usuario'};}

function contactoComunicacionPermitido(PDO $pdo,int $actor,int $contacto):bool
{
 if($actor===$contacto)return false;$a=comunicacionUsuario($pdo,$actor);$c=comunicacionUsuario($pdo,$contacto);if(!$a||!$c)return false;if($a['rol']==='admin'||$c['rol']==='admin')return true;
 if($a['rol']==='docente'){if($c['rol']==='docente')return true;$q=$pdo->prepare("SELECT 1 FROM capacitacion_secciones s JOIN inscripciones_capacitacion i ON i.seccion_id=s.id AND i.estado IN('inscrito','finalizado') WHERE s.docente_id=:a AND i.usuario_id=:c LIMIT 1");$q->execute(['a'=>$actor,'c'=>$contacto]);return(bool)$q->fetchColumn();}
 if($a['rol']==='usuario'&&$c['rol']==='docente'){$q=$pdo->prepare("SELECT 1 FROM inscripciones_capacitacion i JOIN capacitacion_secciones s ON s.id=i.seccion_id WHERE i.usuario_id=:a AND s.docente_id=:c AND i.estado IN('inscrito','finalizado') LIMIT 1");$q->execute(['a'=>$actor,'c'=>$contacto]);return(bool)$q->fetchColumn();}
 if($a['rol']==='usuario'&&$c['rol']==='usuario'){$q=$pdo->prepare("SELECT 1 FROM inscripciones_capacitacion i1 JOIN inscripciones_capacitacion i2 ON i2.seccion_id=i1.seccion_id AND i2.usuario_id=:c AND i2.estado IN('inscrito','finalizado') WHERE i1.usuario_id=:a AND i1.estado IN('inscrito','finalizado') LIMIT 1");$q->execute(['a'=>$actor,'c'=>$contacto]);return(bool)$q->fetchColumn();}return false;
}

function agendaComunicacion(PDO $pdo,int $actor,array $filtros=[]):array
{
 $yo=comunicacionUsuario($pdo,$actor);if(!$yo)return[];$where=["u.id<>:actor","u.estado='activo'","u.deleted_at IS NULL"];$p=['actor'=>$actor];$rol=$filtros['rol']??'';if(in_array($rol,['usuario','docente','admin'],true)){$where[]='u.rol=:rol';$p['rol']=$rol;}$qtxt=trim((string)($filtros['q']??''));if($qtxt!==''){$where[]="(CONCAT_WS(' ',u.nombre,u.apellido) LIKE :q1 OR u.correo LIKE :q2)";$p['q1']=$p['q2']='%'.$qtxt.'%';}$cap=(int)($filtros['capacitacion']??0);if($cap){$where[]="EXISTS(SELECT 1 FROM inscripciones_capacitacion ia LEFT JOIN capacitacion_secciones sa ON sa.id=ia.seccion_id WHERE ia.asignatura_id=:cap AND (ia.usuario_id=u.id OR sa.docente_id=u.id))";$p['cap']=$cap;}$sec=(int)($filtros['seccion']??0);if($sec){$where[]="EXISTS(SELECT 1 FROM inscripciones_capacitacion isec JOIN capacitacion_secciones ss ON ss.id=isec.seccion_id WHERE isec.seccion_id=:sec AND (isec.usuario_id=u.id OR ss.docente_id=u.id))";$p['sec']=$sec;}
 $q=$pdo->prepare('SELECT u.id,u.nombre,u.apellido,u.correo,u.rol FROM usuarios u WHERE '.implode(' AND ',$where).' ORDER BY u.rol,u.nombre,u.apellido LIMIT 300');$q->execute($p);return array_values(array_filter($q->fetchAll(),fn($c)=>contactoComunicacionPermitido($pdo,$actor,(int)$c['id'])));
}

function chatUsuarioBloqueado(PDO $pdo,int $usuario):bool{$q=$pdo->prepare('SELECT 1 FROM chat_bloqueos WHERE usuario_id=:u AND desbloqueado_at IS NULL');$q->execute(['u'=>$usuario]);return(bool)$q->fetchColumn();}
function abrirChatIndividual(PDO $pdo,int $actor,int $contacto):int
{
 if(!contactoComunicacionPermitido($pdo,$actor,$contacto))throw new DomainException('No tienes permiso para contactar a este usuario.');$ids=[$actor,$contacto];sort($ids,SORT_NUMERIC);$clave=hash('sha256',$ids[0].':'.$ids[1]);$pdo->beginTransaction();try{$q=$pdo->prepare("INSERT INTO chat_conversaciones(clave_individual,creado_por) VALUES(:k,:u) ON DUPLICATE KEY UPDATE id=LAST_INSERT_ID(id)");$q->execute(['k'=>$clave,'u'=>$actor]);$id=(int)$pdo->lastInsertId();$q=$pdo->prepare('INSERT IGNORE INTO chat_participantes(conversacion_id,usuario_id) VALUES(:c,:u)');foreach($ids as$u)$q->execute(['c'=>$id,'u'=>$u]);$pdo->commit();return$id;}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();throw$e;}
}
function chatParticipa(PDO $pdo,int $conversacion,int $usuario):bool{$q=$pdo->prepare('SELECT 1 FROM chat_participantes WHERE conversacion_id=:c AND usuario_id=:u AND archivado_at IS NULL');$q->execute(['c'=>$conversacion,'u'=>$usuario]);return(bool)$q->fetchColumn();}
function textoChatSeguro(string $texto):string{$texto=trim(strip_tags($texto));$texto=preg_replace('/[\x00-\x08\x0B\x0C\x0E-\x1F]/u','',$texto)??'';return mb_substr($texto,0,5000);}
function enviarMensajeChat(PDO $pdo,int $conversacion,int $actor,string $texto):int
{
 $texto=textoChatSeguro($texto);if($texto==='')throw new DomainException('El mensaje está vacío.');if(!chatParticipa($pdo,$conversacion,$actor))throw new DomainException('La conversación no te pertenece.');if(chatUsuarioBloqueado($pdo,$actor))throw new DomainException('Tu acceso al chat está bloqueado.');$pdo->beginTransaction();try{$q=$pdo->prepare("INSERT INTO chat_mensajes(conversacion_id,remitente_id,contenido) VALUES(:c,:u,:m)");$q->execute(['c'=>$conversacion,'u'=>$actor,'m'=>$texto]);$id=(int)$pdo->lastInsertId();$pdo->prepare('INSERT INTO chat_lecturas(mensaje_id,usuario_id) VALUES(:m,:u)')->execute(['m'=>$id,'u'=>$actor]);$pdo->prepare('UPDATE chat_conversaciones SET ultimo_mensaje_at=NOW() WHERE id=:c')->execute(['c'=>$conversacion]);$q=$pdo->prepare('SELECT usuario_id FROM chat_participantes WHERE conversacion_id=:c AND usuario_id<>:u');$q->execute(['c'=>$conversacion,'u'=>$actor]);foreach($q->fetchAll(PDO::FETCH_COLUMN) as$destino)crearNotificacionAtenea(['usuario_id'=>(int)$destino,'created_by'=>$actor,'tipo'=>'chat_nuevo','categoria'=>'comunicaciones','nivel'=>'informacion','titulo'=>'Nuevo mensaje interno','descripcion'=>mb_substr($texto,0,160),'url'=>atenea_url('src/comunicaciones/chat.php?id='.$conversacion),'idempotency_key'=>'chat:mensaje:'.$id],$pdo);registrarAuditoria(['actor_user_id'=>$actor,'event_type'=>'chat.message.sent','module'=>'communications','entity_type'=>'chat_message','entity_id'=>$id,'action'=>'create','description'=>'Mensaje interno enviado.'],$pdo);$pdo->commit();return$id;}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();throw$e;}
}
function marcarChatLeido(PDO $pdo,int $conversacion,int $usuario):void{if(!chatParticipa($pdo,$conversacion,$usuario))throw new DomainException('Acceso denegado.');$pdo->prepare('INSERT IGNORE INTO chat_lecturas(mensaje_id,usuario_id) SELECT id,:u FROM chat_mensajes WHERE conversacion_id=:c AND remitente_id<>:u2')->execute(['u'=>$usuario,'c'=>$conversacion,'u2'=>$usuario]);$pdo->prepare('UPDATE chat_participantes SET ultimo_leido_mensaje_id=(SELECT MAX(id) FROM chat_mensajes WHERE conversacion_id=:c) WHERE conversacion_id=:c2 AND usuario_id=:u')->execute(['c'=>$conversacion,'c2'=>$conversacion,'u'=>$usuario]);}

function almacenamientoComunicacionBase():string{return rtrim(AppConfig::value('COMMUNICATION_STORAGE_PATH',dirname(ATENEA_ROOT).'/atenea-private/comunicaciones'),'/\\');}
function rutaPrivadaComunicacion(string $rel):?string{if($rel===''||str_contains($rel,'..')||preg_match('/[^A-Za-z0-9_\/.\-]/',$rel))return null;$base=almacenamientoComunicacionBase();$root=realpath($base);$ruta=realpath($base.DIRECTORY_SEPARATOR.str_replace('/',DIRECTORY_SEPARATOR,$rel));return$root&&$ruta&&str_starts_with(strtolower($ruta),strtolower($root.DIRECTORY_SEPARATOR))&&is_file($ruta)?$ruta:null;}
function guardarAdjuntoComunicacion(string $campo,string $carpeta='adjuntos'):?array{if(!isset($_FILES[$campo])||($_FILES[$campo]['error']??UPLOAD_ERR_NO_FILE)===UPLOAD_ERR_NO_FILE)return null;$f=$_FILES[$campo];if($f['error']!==UPLOAD_ERR_OK||(int)$f['size']<1||(int)$f['size']>10*1024*1024)throw new DomainException('Adjunto vacío o mayor de 10 MB.');$permitidos=['application/pdf'=>'pdf','application/msword'=>'doc','application/vnd.openxmlformats-officedocument.wordprocessingml.document'=>'docx','image/jpeg'=>'jpg','image/png'=>'png','image/webp'=>'webp','text/plain'=>'txt'];$mime=(new finfo(FILEINFO_MIME_TYPE))->file($f['tmp_name']);if(!isset($permitidos[$mime]))throw new DomainException('Tipo de adjunto no permitido.');$ext=strtolower(pathinfo((string)$f['name'],PATHINFO_EXTENSION));$validas=$permitidos[$mime]==='jpg'?['jpg','jpeg']:[$permitidos[$mime]];if(!in_array($ext,$validas,true)||preg_match('/\.(php\d*|phtml|phar|html?|svg|exe|js|sh)(\.|$)/i',(string)$f['name']))throw new DomainException('La extensión del adjunto no es segura.');$dir=almacenamientoComunicacionBase().DIRECTORY_SEPARATOR.$carpeta;if(!is_dir($dir)&&!mkdir($dir,0700,true)&&!is_dir($dir))throw new RuntimeException('No se pudo crear el almacenamiento privado.');$nombre=bin2hex(random_bytes(24)).'.'.$permitidos[$mime];if(!move_uploaded_file($f['tmp_name'],$dir.DIRECTORY_SEPARATOR.$nombre))throw new RuntimeException('No se pudo guardar el adjunto.');return['relpath'=>$carpeta.'/'.$nombre,'nombre'=>mb_substr(basename((string)$f['name']),0,190),'mime'=>$mime,'tamano'=>(int)$f['size']];}

function decodificarCabeceraImap(string $valor):string{if(function_exists('imap_mime_header_decode')){$salida='';foreach(imap_mime_header_decode($valor) as$p)$salida.=$p->text;return mb_substr(trim($salida),0,190);}return mb_substr(trim($valor),0,190);}
function guardarAdjuntosImapAtenea(mixed $imap,int $numero,mixed $estructura,int $mensajeId,PDO $pdo,string $prefijo=''):void
{
 $partes=$estructura->parts??[];foreach($partes as$i=>$parte){$n=$prefijo===''?(string)($i+1):$prefijo.'.'.($i+1);if(!empty($parte->parts)){guardarAdjuntosImapAtenea($imap,$numero,$parte,$mensajeId,$pdo,$n);continue;}$nombre='';foreach(array_merge($parte->dparameters??[],$parte->parameters??[]) as$p)if(in_array(strtolower((string)($p->attribute??'')),['filename','name'],true))$nombre=decodificarCabeceraImap((string)$p->value);if($nombre==='')continue;$sub=strtolower((string)($parte->subtype??''));$tipo=(int)($parte->type??0);$mime=match($tipo){0=>'text/'.$sub,2=>'message/'.$sub,3=>'application/'.$sub,4=>'audio/'.$sub,5=>'image/'.$sub,6=>'video/'.$sub,default=>'application/octet-stream'};$permitidos=['application/pdf'=>'pdf','application/msword'=>'doc','application/vnd.openxmlformats-officedocument.wordprocessingml.document'=>'docx','image/jpeg'=>'jpg','image/png'=>'png','image/webp'=>'webp','text/plain'=>'txt'];if(!isset($permitidos[$mime]))continue;$datos=(string)imap_fetchbody($imap,$numero,$n,FT_PEEK);if((int)($parte->encoding??0)===3)$datos=base64_decode($datos,true)?:'';elseif((int)($parte->encoding??0)===4)$datos=quoted_printable_decode($datos);if($datos===''||strlen($datos)>10*1024*1024)continue;$dir=almacenamientoComunicacionBase().DIRECTORY_SEPARATOR.'correo';if(!is_dir($dir)&&!mkdir($dir,0700,true)&&!is_dir($dir))continue;$archivo=bin2hex(random_bytes(24)).'.'.$permitidos[$mime];if(file_put_contents($dir.DIRECTORY_SEPARATOR.$archivo,$datos,LOCK_EX)===false)continue;$q=$pdo->prepare('INSERT INTO correo_centro_adjuntos(mensaje_id,archivo_relpath,archivo_nombre,archivo_mime,archivo_tamano) VALUES(:m,:r,:n,:mime,:t)');$q->execute(['m'=>$mensajeId,'r'=>'correo/'.$archivo,'n'=>mb_substr(basename($nombre),0,190),'mime'=>$mime,'t'=>strlen($datos)]);}
}
function sincronizarImapAteneaLegacy(PDO $pdo):array
{
 if(!imapAteneaConfigurado())throw new RuntimeException('IMAP no está configurado o la extensión PHP IMAP no está habilitada.');$c=configuracionImapAtenea();$flags=$c['encryption']==='none'?'/novalidate-cert':'/'.$c['encryption'];$buzon='{'.$c['host'].':'.$c['port'].'/imap'.$flags.'}'.$c['folder'];$imap=@imap_open($buzon,$c['user'],$c['password'],0,1);if(!$imap){$error=mb_substr((string)imap_last_error(),0,500);$pdo->prepare("INSERT INTO correo_imap_estado(carpeta,ultimo_error,ultima_sincronizacion_at) VALUES(:c,:e,NOW()) ON DUPLICATE KEY UPDATE ultimo_error=:e2,ultima_sincronizacion_at=NOW()")->execute(['c'=>$c['folder'],'e'=>$error,'e2'=>$error]);throw new RuntimeException('No fue posible conectar con IMAP: '.$error);}$q=$pdo->prepare('SELECT ultimo_uid FROM correo_imap_estado WHERE carpeta=:c');$q->execute(['c'=>$c['folder']]);$ultimo=(int)$q->fetchColumn();$uids=imap_search($imap,'UID '.($ultimo+1).':*',SE_UID)?:[];$nuevos=0;foreach($uids as$uid){if((int)$uid<=$ultimo)continue;$num=imap_msgno($imap,(int)$uid);$h=imap_headerinfo($imap,$num);$from=strtolower((string)($h->from[0]->mailbox??'').'@'.(string)($h->from[0]->host??''));$to=strtolower((string)($h->to[0]->mailbox??'').'@'.(string)($h->to[0]->host??''));$asunto=decodificarCabeceraImap((string)($h->subject??'Sin asunto'));$messageId=trim((string)($h->message_id??''))?:null;$body=(string)imap_fetchbody($imap,$num,'1',FT_PEEK);if($body==='')$body=(string)imap_body($imap,$num,FT_PEEK);if((int)($h->encoding??0)===3)$body=base64_decode($body,true)?:$body;elseif((int)($h->encoding??0)===4)$body=quoted_printable_decode($body);$body=mb_substr(trim(strip_tags($body)),0,100000);$q=$pdo->prepare('SELECT id FROM usuarios WHERE LOWER(correo)=:c LIMIT 1');$q->execute(['c'=>$from]);$usuario=$q->fetchColumn()?:null;$pdo->beginTransaction();try{$q=$pdo->prepare('INSERT INTO correo_centro_hilos(asunto,usuario_relacionado_id,ultimo_mensaje_at) VALUES(:a,:u,NOW())');$q->execute(['a'=>$asunto,'u'=>$usuario]);$hilo=(int)$pdo->lastInsertId();$q=$pdo->prepare("INSERT IGNORE INTO correo_centro_mensajes(hilo_id,direccion,remitente,destinatario,asunto,contenido_texto,message_id_servidor,uid_imap,carpeta_imap,estado,enviado_recibido_at) VALUES(:h,'entrada',:r,:d,:a,:m,:mid,:uid,:carpeta,'recibido',FROM_UNIXTIME(:fecha))");$q->execute(['h'=>$hilo,'r'=>$from,'d'=>$to,'a'=>$asunto,'m'=>$body?:'[Mensaje sin contenido de texto]','mid'=>$messageId,'uid'=>$uid,'carpeta'=>$c['folder'],'fecha'=>(int)($h->udate??time())]);if($q->rowCount()===0)$pdo->prepare('DELETE FROM correo_centro_hilos WHERE id=:h')->execute(['h'=>$hilo]);else{$mensajeCorreo=(int)$pdo->lastInsertId();guardarAdjuntosImapAtenea($imap,$num,imap_fetchstructure($imap,$num),$mensajeCorreo,$pdo);$nuevos++;if($usuario)crearNotificacionAtenea(['rol'=>'admin','tipo'=>'correo_recibido','categoria'=>'comunicaciones','nivel'=>'informacion','titulo'=>'Correo recibido: '.$asunto,'descripcion'=>mb_substr($body,0,160),'url'=>atenea_url('src/comunicaciones/correo-hilo.php?id='.$hilo),'idempotency_key'=>'imap:'.$c['folder'].':'.$uid],$pdo);}$pdo->commit();$ultimo=max($ultimo,(int)$uid);}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();throw$e;}}imap_close($imap);$pdo->prepare("INSERT INTO correo_imap_estado(carpeta,ultimo_uid,ultima_sincronizacion_at,ultimo_error) VALUES(:c,:u,NOW(),NULL) ON DUPLICATE KEY UPDATE ultimo_uid=GREATEST(ultimo_uid,:u2),ultima_sincronizacion_at=NOW(),ultimo_error=NULL")->execute(['c'=>$c['folder'],'u'=>$ultimo,'u2'=>$ultimo]);return['nuevos'=>$nuevos,'ultimo_uid'=>$ultimo];
}

function sincronizarImapAtenea(PDO $pdo): array
{
    $c=ImapConfig::toArray();$imap=abrirImapAtenea();$nuevos=0;
    try{
        $q=$pdo->prepare('SELECT ultimo_uid FROM correo_imap_estado WHERE carpeta=:c');$q->execute(['c'=>$c['folder']]);$ultimo=(int)$q->fetchColumn();$uids=imap_search($imap,'UID '.($ultimo+1).':*',SE_UID)?:[];
        foreach($uids as$uid){
            if((int)$uid<=$ultimo)continue;$numero=imap_msgno($imap,(int)$uid);$cabecera=imap_headerinfo($imap,$numero);$remitente=strtolower((string)($cabecera->from[0]->mailbox??'').'@'.(string)($cabecera->from[0]->host??''));$destinatario=strtolower((string)($cabecera->to[0]->mailbox??'').'@'.(string)($cabecera->to[0]->host??''));$asunto=decodificarCabeceraImap((string)($cabecera->subject??'Sin asunto'));$messageId=trim((string)($cabecera->message_id??''))?:null;$contenido=(string)imap_fetchbody($imap,$numero,'1',FT_PEEK);if($contenido==='')$contenido=(string)imap_body($imap,$numero,FT_PEEK);$contenido=mb_substr(trim(strip_tags($contenido)),0,100000);$q=$pdo->prepare('SELECT id FROM usuarios WHERE LOWER(correo)=:correo LIMIT 1');$q->execute(['correo'=>$remitente]);$usuario=$q->fetchColumn()?:null;
            $pdo->beginTransaction();
            try{$q=$pdo->prepare('INSERT INTO correo_centro_hilos(asunto,usuario_relacionado_id,ultimo_mensaje_at) VALUES(:asunto,:usuario,NOW())');$q->execute(['asunto'=>$asunto,'usuario'=>$usuario]);$hilo=(int)$pdo->lastInsertId();$q=$pdo->prepare("INSERT IGNORE INTO correo_centro_mensajes(hilo_id,direccion,remitente,destinatario,asunto,contenido_texto,message_id_servidor,uid_imap,carpeta_imap,estado,enviado_recibido_at) VALUES(:hilo,'entrada',:remitente,:destinatario,:asunto,:contenido,:message_id,:uid,:carpeta,'recibido',FROM_UNIXTIME(:fecha))");$q->execute(['hilo'=>$hilo,'remitente'=>$remitente,'destinatario'=>$destinatario,'asunto'=>$asunto,'contenido'=>$contenido?:'[Mensaje sin contenido de texto]','message_id'=>$messageId,'uid'=>$uid,'carpeta'=>$c['folder'],'fecha'=>(int)($cabecera->udate??time())]);if($q->rowCount()===0)$pdo->prepare('DELETE FROM correo_centro_hilos WHERE id=:id')->execute(['id'=>$hilo]);else{$mensaje=(int)$pdo->lastInsertId();guardarAdjuntosImapAtenea($imap,$numero,imap_fetchstructure($imap,$numero),$mensaje,$pdo);$nuevos++;if($usuario)crearNotificacionAtenea(['rol'=>'admin','tipo'=>'correo_recibido','categoria'=>'comunicaciones','nivel'=>'informacion','titulo'=>'Correo recibido: '.$asunto,'descripcion'=>mb_substr($contenido,0,160),'url'=>atenea_url('src/comunicaciones/correo-hilo.php?id='.$hilo),'idempotency_key'=>'imap:'.$c['folder'].':'.$uid],$pdo);}$pdo->commit();$ultimo=max($ultimo,(int)$uid);}catch(Throwable $error){if($pdo->inTransaction())$pdo->rollBack();throw$error;}
        }
        $q=$pdo->prepare("INSERT INTO correo_imap_estado(carpeta,ultimo_uid,ultima_sincronizacion_at,ultimo_error) VALUES(:carpeta,:uid,NOW(),NULL) ON DUPLICATE KEY UPDATE ultimo_uid=GREATEST(ultimo_uid,:uid2),ultima_sincronizacion_at=NOW(),ultimo_error=NULL");$q->execute(['carpeta'=>$c['folder'],'uid'=>$ultimo,'uid2'=>$ultimo]);return['nuevos'=>$nuevos,'ultimo_uid'=>$ultimo];
    }finally{imap_close($imap);}
}
